    {9, 8, 7},
    {6, 5, 4},
    {3, 2, 1}
};

// Define output matrix
int result[SIZE][SIZE];

// Assembly function to multiply two matrices
extern void MatrixMultiply(int*, int*, int*, int);

// Main function
int main() {
    // Call assembly function to multiply matrices
    MatrixMultiply(&mat1[0][0], &mat2[0][0], &result[0][0], SIZE);

    // Print result matrix
    for (int i = 0; i < SIZE; i++) {
        for (int j = 0; j < SIZE; j++) {
            printf("%d ", result[i][j]);
        }
        printf("\n");
    }

    return 0;
}
